import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  it("single live cell dies — [(0,0)] becomes []", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
  });
  it("Rule 1 Underpopulation: two adjacent cells [(0,1),(1,1)] each have 1 neighbor and die — becomes []", () => {
    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
  });
  it("Rule 3 Overpopulation: ###/.#./### — center (1,1) has 6 live neighbors and dies", () => {
    const input: [number, number][] = [
      [0, 0], [1, 0], [2, 0],
              [1, 1],
      [0, 2], [1, 2], [2, 2],
    ];
    const result = nextGeneration(input);
    const keys = new Set(result.map(c => c.join(",")));
    expect(keys.has("1,1")).toBe(false);
  });
  it("Rule 4 Reproduction: ##./#../... — dead cell (1,1) has 3 live neighbors and becomes alive, yielding the block ##./##.", () => {
    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
    const result = nextGeneration(input);
    expect(new Set(result.map(c => c.join(",")))).toEqual(
      new Set([[0, 0], [1, 0], [0, 1], [1, 1]].map(c => c.join(",")))
    );
  });
  it.todo("Rule 2 Survival: T-shape [(0,2),(1,2),(2,2),(1,0)] center (1,1) has 3 neighbors and lives — (1,1) alive in next gen");
  it.todo("Block still life [(0,0),(1,0),(0,1),(1,1)] is unchanged");
  it.todo("Blinker vertical [(0,0),(0,1),(0,2)] becomes horizontal [(-1,1),(0,1),(1,1)]");
  it.todo("Blinker horizontal [(-1,1),(0,1),(1,1)] becomes vertical [(0,0),(0,1),(0,2)]");
  it.todo("handles negative coordinates — single cell at (-5,-5) dies, returns []");
});

